import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.Cqf6AMW8.js";const _=JSON.parse('{"title":"JavaScript GC机制","description":"JavaScript 垃圾回收机制相关知识。","frontmatter":{"title":"JavaScript GC机制","description":"JavaScript 垃圾回收机制相关知识。","date":"2026-04-21T00:00:00.000Z","tags":["JavaScript","GC机制","内存管理"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/javascript/JS-DOM-2-GC机制.md","filePath":"docs/frontend/javascript/JS-DOM-2-GC机制.md","lastUpdated":1776715536000}'),o={name:"docs/frontend/javascript/JS-DOM-2-GC机制.md"};function i(h,t,n,c,p,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<p>#JavaScript</p><p>======================================================</p><h2 id="垃圾回收机制" tabindex="-1">垃圾回收机制 <a class="header-anchor" href="#垃圾回收机制" aria-label="Permalink to &quot;垃圾回收机制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>定义</td><td>JavaScript 中内存的分配和回收都是自动完成的，内存在不使用的时候会被垃圾回收器自动回收</td></tr><tr><td>垃圾回收机制的作用</td><td>找出不再使用的变量，然后释放掉它们占用的内存</td></tr><tr><td>内存泄漏</td><td>内存泄漏是指程序中己动态分配的堆内存由于某种原因程序未释放或无法释放，造成系统内存的浪费，导致程序运行速度减慢甚至系统崩溃等严重后果</td></tr></tbody></table><p>======================================================</p><h2 id="垃圾回收策略" tabindex="-1">垃圾回收策略 <a class="header-anchor" href="#垃圾回收策略" aria-label="Permalink to &quot;垃圾回收策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>垃圾回收策略</th><th>描述</th></tr></thead><tbody><tr><td>标记清除</td><td>标记清除是目前主流的垃圾回收算法，当变量进入环境时，就标记这个变量为&quot;进入环境&quot;，当变量离开环境时，就标记为&quot;离开环境&quot;</td></tr><tr><td>引用计数</td><td>引用计数是跟踪记录每个值被引用的次数，当一个值的引用次数变为 0 时，就表示这个值不再被需要，因此可以将其占用的内存空间回收</td></tr></tbody></table><p>======================================================</p><h2 id="常见内存泄漏情况" tabindex="-1">常见内存泄漏情况 <a class="header-anchor" href="#常见内存泄漏情况" aria-label="Permalink to &quot;常见内存泄漏情况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>常见内存泄漏情况</th><th>描述</th></tr></thead><tbody><tr><td>意外的全局变量</td><td>全局变量不会被回收，除非页面被关闭</td></tr><tr><td>被遗忘的计时器或回调函数</td><td>定时器或回调函数未被清除时，其引用的变量也不会被回收</td></tr><tr><td>闭包</td><td>闭包会保持对外部变量的引用，导致这些变量不会被回收</td></tr></tbody></table><p>======================================================</p>',11)])])}const b=a(o,[["render",i]]);export{_ as __pageData,b as default};
